SELECT *
FROM note_share
WHERE note_id = #{noteId}
  AND user_id = #{userId}
ORDER BY created_at DESC

SELECT COUNT(*)
FROM note_share
WHERE note_id = #{noteId}
  AND user_id = #{userId}
  AND disabled = FALSE
  AND (expires_at IS NULL OR expires_at > CURRENT_TIMESTAMP)

mapper.update:
UPDATE note_share
SET disabled = TRUE
WHERE id = #{id}
  AND user_id = #{userId}
